function renderSummary(){if(!state.runtime)return;const wifi=state.runtime.wifi||{};const detectedChip=state.runtime.detected_chip||{};$('summaryWifiMode').textContent=((wifi.mode||'-')+'').toUpperCase();$('summaryIp').textContent=state.runtime.ip||'-';$('summaryChip').textContent=detectedChip.model||'-';$('summaryBoard').textContent=state.runtime.active_board||'-';$('runtimeOverview').textContent=JSON.stringify(state.runtime,null,2);$('templateChainOverview').textContent='Board instance: '+(state.runtime.active_board||'-')+'\nBoard template: '+(state.runtime.board_template||'-')+'\nChip template: '+(state.runtime.chip_template||'-')+'\nDetected chip: '+(detectedChip.model||'-')+' rev.'+(detectedChip.revision??'-');$('chipOverview').textContent=JSON.stringify(state.chip,null,2);const detected=(detectedChip.model||'').toLowerCase();const selected=(state.runtime.chip_template||'').toLowerCase();const warning=[];if(detected.includes('esp32')&&!selected.includes('esp32'))warning.push('Detected chip looks like ESP32, but selected chip template does not.');if(detected.includes('8266')&&!selected.includes('8266'))warning.push('Detected chip looks like ESP8266, but selected chip template does not.');if(state.runtime.board_template&&state.templates?.board_templates?.[state.runtime.board_template]){const derived=state.templates.board_templates[state.runtime.board_template].chip_template||'';if(derived&&state.runtime.chip_template&&derived!==state.runtime.chip_template&&state.templates.active_chip_template)warning.push('Chip override differs from the chip template declared by the active board template.')}const box=$('templateWarningBox');if(warning.length){box.textContent=warning.join(' ');box.classList.remove('hidden')}else{box.textContent='';box.classList.add('hidden')}const pins=state.hardware?.pins||[];const channels=Object.entries(state.channels?.channels||{});const alarms=Object.entries(state.alarms?.alarms||{});const activeAlarms=alarms.filter(([,alarm])=>alarm.active);const pendingAlarms=alarms.filter(([,alarm])=>alarm.pending);const unackedAlarms=alarms.filter(([,alarm])=>alarm.active&&alarm.ack_required&&!alarm.acknowledged);const sequences=Object.entries(state.sequences?.sequences||{});const runningSequences=sequences.filter(([,sequence])=>sequence.running);const faultSequences=sequences.filter(([,sequence])=>sequence.fault);const availablePins=pins.filter(pin=>pin.available).length;const warningPins=pins.filter(pin=>pin.class==='warning').length;const sharedPins=pins.filter(pin=>pin.class==='shared').length;const typeCount={di:0,do:0,ai:0};channels.forEach(([,c])=>{if(typeCount[c.type]!==undefined)typeCount[c.type]++});$('ovChannelCount').textContent=String(channels.length);$('ovAvailablePins').textContent=String(availablePins);$('ovWarningPins').textContent=String(warningPins);$('ovSharedPins').textContent=String(sharedPins);$('controllerOverview').innerHTML='<div><span>Board instance</span><strong>'+(state.runtime.active_board||'-')+'</strong></div><div><span>Board template</span><strong>'+(state.runtime.board_template||'-')+'</strong></div><div><span>Chip template</span><strong>'+(state.runtime.chip_template||'-')+'</strong></div><div><span>Detected chip</span><strong>'+(detectedChip.model||'-')+'</strong></div>';$('healthOverview').innerHTML='<div><span>Wi-Fi mode</span><strong>'+(wifi.mode||'-')+'</strong></div><div><span>IP address</span><strong>'+(state.runtime.ip||'-')+'</strong></div><div><span>OLED</span><strong>'+((state.runtime.modules?.oled)?'enabled':'off')+'</strong></div><div><span>LoRa</span><strong>'+((state.runtime.modules?.lora)?'enabled':'off')+'</strong></div><div><span>SD</span><strong>'+((state.runtime.modules?.sd)?'enabled':'off')+'</strong></div><div><span>Warnings</span><strong>'+(warning.length?warning.length:'0')+'</strong></div>';$('ioOverview').innerHTML='<div><span>Digital inputs</span><strong>'+typeCount.di+'</strong></div><div><span>Digital outputs</span><strong>'+typeCount.do+'</strong></div><div><span>Analog inputs</span><strong>'+typeCount.ai+'</strong></div><div><span>Configured channels</span><strong>'+channels.length+'</strong></div><div><span>Available pins</span><strong>'+availablePins+'</strong></div><div><span>Shared / warning pins</span><strong>'+sharedPins+' / '+warningPins+'</strong></div>';if($('alarmOverview'))$('alarmOverview').innerHTML='<div><span>Active alarms</span><strong>'+activeAlarms.length+'</strong></div><div><span>Pending</span><strong>'+pendingAlarms.length+'</strong></div><div><span>Need ack</span><strong>'+unackedAlarms.length+'</strong></div><div><span>Latest active</span><strong>'+(activeAlarms[0]?.[1]?.label||activeAlarms[0]?.[0]||'-')+'</strong></div>';if($('sequenceOverview'))$('sequenceOverview').innerHTML='<div><span>Running sequences</span><strong>'+runningSequences.length+'</strong></div><div><span>Faulted</span><strong>'+faultSequences.length+'</strong></div><div><span>Total</span><strong>'+sequences.length+'</strong></div><div><span>Current</span><strong>'+(runningSequences[0]?.[1]?.current_state_label||runningSequences[0]?.[1]?.current_state||'-')+'</strong></div>'}
function renderHardware(){const pins=state.hardware?.pins||[];const rows=pins.map(pin=>{const traits=[];if(pin.internal_pullup)traits.push('pullup');if(pin.input_only)traits.push('input-only');if(pin.strapping)traits.push('strap');if(pin.available)traits.push('available');return '<tr><td>GPIO'+pin.gpio+'</td><td><span class="badge '+pin.class+'">'+pin.class+'</span></td><td>'+(pin.owner||'-')+'</td><td>'+(pin.reason||'-')+'</td><td>'+(pin.resource||'-')+'</td><td>'+(pin.channel||'-')+'</td><td>'+(traits.join(', ')||'-')+'</td></tr>'}).join('');$('hardwareTable').innerHTML=rows||'<tr><td colspan="7">No hardware map available</td></tr>';const safePins=pins.filter(pin=>pin.class==='safe').length;const warningPins=pins.filter(pin=>pin.class==='warning').length;const sharedPins=pins.filter(pin=>pin.class==='shared').length;const exclusivePins=pins.filter(pin=>pin.class==='exclusive').length;const forbiddenPins=pins.filter(pin=>pin.class==='forbidden').length;const assignedPins=pins.filter(pin=>pin.channel).length;const runtimeModules=Object.entries(state.runtime?.modules||{}).filter(([,enabled])=>!!enabled).map(([key])=>key);if($('hardwarePolicySummary'))$('hardwarePolicySummary').innerHTML='<div><span>Board instance</span><strong>'+(state.runtime?.active_board||'-')+'</strong></div><div><span>Board template</span><strong>'+(state.runtime?.board_template||'-')+'</strong></div><div><span>Chip template</span><strong>'+(state.runtime?.chip_template||'-')+'</strong></div><div><span>Safe / warning</span><strong>'+safePins+' / '+warningPins+'</strong></div><div><span>Shared / exclusive</span><strong>'+sharedPins+' / '+exclusivePins+'</strong></div><div><span>Forbidden / assigned</span><strong>'+forbiddenPins+' / '+assignedPins+'</strong></div>';if($('hardwarePolicyNote'))$('hardwarePolicyNote').textContent='Active modules: '+(runtimeModules.join(', ')||'none')+'. Live hardware map rows below already include board template rules, module reservations and current channel ownership.'}
function renderChannels(){const statusMap=state.status?.channels||{};const channelRows=Object.entries(state.channels?.channels||{}).map(([id,c])=>{const flags=[];if(c.source_kind==='external')flags.push('external');if(c.inverted)flags.push('inverted');if(c.pullup)flags.push('pullup');if(c.initial)flags.push('initial');if((c.type==='ai'||c.type==='ao')&&c.profile)flags.push(c.profile);if(c.units)flags.push(c.units);if(c.auto_generated)flags.push(t('generated')+(c.generated_by?(' '+c.generated_by):''));const runtime=statusMap[id]||{};const ext=c.source_kind==='external'&&c.resource?state.externalResources?.external_resources?.[c.resource]:null;const device=ext?.device_id?state.devices?.devices?.[ext.device_id]:null;const gpio=runtime.external?'EXT':(runtime.gpio!==undefined&&runtime.gpio>=0?('GPIO'+runtime.gpio):'-');const value=runtime.value!==undefined?String(runtime.value):'n/a';let resourceLabel=c.source_label?c.resource+' - '+c.source_label:(c.resource||'-');if(ext){const resourceBits=[];if(ext.device_id)resourceBits.push(ext.device_id);if(device?.driver)resourceBits.push(device.driver);if((c.type==='ai'||c.type==='ao')&&ext.raw_value!==undefined)resourceBits.push('raw '+ext.raw_value);if(ext.status)resourceBits.push(ext.status);resourceLabel+='<div class="muted-line">'+resourceBits.join(' | ')+'</div>'}return '<tr><td>'+id+'</td><td>'+c.type+'</td><td>'+resourceLabel+'</td><td>'+gpio+'</td><td>'+value+'</td><td>'+(flags.join(', ')||'-')+'</td><td><div class="row-actions"><button data-edit-channel="'+id+'">Edit</button><button data-delete-channel="'+id+'">Delete</button></div></td></tr>'}).join('');$('channelsTable').innerHTML=channelRows||'<tr><td colspan="7">No channels configured</td></tr>';const statusRows=Object.entries(statusMap).map(([id,c])=>{const source=c.external?'EXT':(c.gpio!==undefined&&c.gpio>=0?('GPIO'+c.gpio):'-');return '<tr><td>'+id+'</td><td>'+source+'</td><td>'+c.type+'</td><td>'+(c.value!==undefined?c.value:'n/a')+'</td></tr>'}).join('');$('statusTable').innerHTML=statusRows||'<tr><td colspan="4">No runtime status available</td></tr>'}
function renderChannelExternalOptions(){const selectedType=$('channelType')?.value||'di';const options=Object.entries(state.externalResources?.external_resources||{}).filter(([,resource])=>resource.capability===selectedType).map(([id,resource])=>'<option value="'+id+'">'+id+' - '+(resource.label||id)+(resource.device_id?(' ('+resource.device_id+')'):'')+'</option>').join('');$('channelExternalResource').innerHTML=options||'<option value="">Нет внешних ресурсов</option>'}
function pinPolicyRank(pinClass){switch(pinClass){case'warning':return 1;case'shared':return 1;case'exclusive':return 2;case'forbidden':return 3;default:return 0}}
function getUiActiveBoardTemplate(){const activeBoard=state.runtime?.active_board||state.boards?.active||'';const board=activeBoard?state.boards?.list?.[activeBoard]:null;const runtimeTemplate=state.runtime?.board_template||'';const boardTemplateId=runtimeTemplate||board?.template||'';return boardTemplateId?state.templates?.board_templates?.[boardTemplateId]||null:null}
function getUiActiveChipTemplate(){const boardTemplate=getUiActiveBoardTemplate();const chipTemplateId=state.runtime?.chip_template||boardTemplate?.chip_template||'';return chipTemplateId?state.templates?.chip_templates?.[chipTemplateId]||null:null}
function isBoardFeatureEnabledForUi(featureKey){if(featureKey==='usb_uart'||featureKey==='boot')return true;return !!state.runtime?.modules?.[featureKey]}
function cloneTemplatePinForUi(gpio,pinConfig){return{gpio,available:!pinConfig?.forbidden,class:pinConfig?.forbidden?'forbidden':'safe',owner:'',reason:pinConfig?.note||'',resource:'',channel:'',internal_pullup:!!pinConfig?.internal_pullup,input_only:!!pinConfig?.input_only,strapping:!!pinConfig?.strapping,capabilities:Array.isArray(pinConfig?.capabilities)?pinConfig.capabilities.slice():[]}}
function applyBoardTemplateRulesForUi(pin){const boardTemplate=getUiActiveBoardTemplate();if(!boardTemplate?.rules)return pin;const next={...pin};Object.values(boardTemplate.rules||{}).forEach(rule=>{if(!rule)return;const pins=Array.isArray(rule.pins)?rule.pins:[];const applies=!!rule.always_on||isBoardFeatureEnabledForUi(rule.feature);if(!applies||!pins.includes(next.gpio))return;const nextClass=(rule.class||'safe')+'';if(pinPolicyRank(nextClass)<pinPolicyRank(next.class||'safe'))return;next.class=nextClass;next.available=nextClass!=='exclusive'&&nextClass!=='forbidden';next.owner=rule.owner||next.owner||'';next.reason=rule.reason||next.reason||''});return next}
function currentEditingChannelId(){return $('channelId')?.value?.trim?.()||''}
function currentEditingChannelGpio(){const channelId=currentEditingChannelId();const runtime=state.status?.channels?.[channelId];if(runtime&&runtime.gpio!==undefined&&runtime.gpio>=0)return runtime.gpio;const selected=parseInt($('channelGpio')?.value,10);return Number.isFinite(selected)&&selected>=0?selected:null}
function buildFallbackHardwarePinsForChannelUi(){const chipTemplate=getUiActiveChipTemplate();const templatePins=chipTemplate?.pins||{};const fallbackPins=Object.entries(templatePins).map(([gpio,pinConfig])=>applyBoardTemplateRulesForUi(cloneTemplatePinForUi(parseInt(gpio,10),pinConfig)));const channelRuntime=state.status?.channels||{};const editingId=currentEditingChannelId();Object.entries(channelRuntime).forEach(([channelId,channel])=>{if(channel?.external||channel?.gpio===undefined||channel.gpio<0)return;const target=fallbackPins.find(pin=>pin.gpio===channel.gpio);if(!target)return;target.channel=channelId;if(channelId!==editingId&&target.class!=='exclusive'&&target.class!=='forbidden'){target.available=false;target.reason=target.reason||'Already assigned to another channel'}});return fallbackPins}
function buildHardwarePinsForChannelUi(){const livePins=Array.isArray(state.hardware?.pins)?state.hardware.pins:[];const chipTemplate=getUiActiveChipTemplate();const templatePins=chipTemplate?.pins||{};if(livePins.length){return livePins.map(pin=>{const templatePin=templatePins[String(pin.gpio)]||null;return{...pin,capabilities:Array.isArray(templatePin?.capabilities)?templatePin.capabilities.slice():[]}})}return buildFallbackHardwarePinsForChannelUi()}
function pinSupportsChannelType(pin,selectedType){const capabilities=Array.isArray(pin.capabilities)?pin.capabilities:[];if(selectedType==='do'&&pin.input_only)return false;if(selectedType==='ao'&&pin.input_only)return false;if(!capabilities.length)return true;if(selectedType==='di')return capabilities.includes('di');if(selectedType==='do')return capabilities.includes('do');if(selectedType==='ai')return capabilities.includes('ai');return true}
function getChannelEligiblePins(selectedType){const editingId=currentEditingChannelId();const editingGpio=currentEditingChannelGpio();const collect=(pins)=>pins.filter(pin=>{const isCurrentPin=editingGpio!==null&&pin.gpio===editingGpio;const blockedClass=pin.class==='exclusive'||pin.class==='forbidden';const blockedByChannel=!!pin.channel&&pin.channel!==editingId;const availableForNew=pin.available!==false&&!blockedClass&&!blockedByChannel;return (availableForNew||isCurrentPin)&&pinSupportsChannelType(pin,selectedType)}).sort((a,b)=>a.gpio-b.gpio);const liveEligible=collect(buildHardwarePinsForChannelUi());if(liveEligible.length||!Array.isArray(state.hardware?.pins)||!state.hardware.pins.length)return liveEligible;return collect(buildFallbackHardwarePinsForChannelUi())}
function renderChannelOptions(){const selectedType=$('channelType')?.value||'di';const editingId=currentEditingChannelId();const editingGpio=currentEditingChannelGpio();const allPins=buildHardwarePinsForChannelUi();const eligiblePins=getChannelEligiblePins(selectedType);const options=eligiblePins.map(pin=>{const bits=[pin.class||'safe'];if(pin.reason)bits.push(pin.reason);if(pin.channel&&pin.gpio===editingGpio)bits.push('editing current assignment');return '<option value="'+pin.gpio+'">GPIO'+pin.gpio+' - '+escapeHtml(bits.join(' - '))+'</option>'}).join('');$('channelGpio').innerHTML=options||'<option value="">No available pins</option>';if(editingGpio!==null&&eligiblePins.some(pin=>pin.gpio===editingGpio))$('channelGpio').value=String(editingGpio);const blockedByType=allPins.filter(pin=>!pinSupportsChannelType(pin,selectedType)).length;const blockedByPolicy=allPins.filter(pin=>(pin.class==='exclusive'||pin.class==='forbidden')&&(editingGpio===null||pin.gpio!==editingGpio)).length;const blockedByChannel=allPins.filter(pin=>!!pin.channel&&pin.channel!==editingId&&(editingGpio===null||pin.gpio!==editingGpio)).length;if($('channelPolicySummary'))$('channelPolicySummary').innerHTML='<div><span>Candidate pins</span><strong>'+allPins.length+'</strong></div><div><span>Eligible for '+selectedType.toUpperCase()+'</span><strong>'+eligiblePins.length+'</strong></div><div><span>Blocked by type</span><strong>'+blockedByType+'</strong></div><div><span>Blocked by policy</span><strong>'+blockedByPolicy+'</strong></div><div><span>Blocked by channel use</span><strong>'+blockedByChannel+'</strong></div><div><span>Editing channel</span><strong>'+(editingId||'new')+'</strong></div>';if($('channelPolicyNote'))$('channelPolicyNote').textContent=eligiblePins.length?'GPIO list already includes current board/chip templates, active module reservations and existing channel ownership.':'No GPIO passed the current filter. Check board template, active modules, channel ownership and selected channel type.';renderChannelExternalOptions();updateChannelSourceVisibility()}
function getSelectedExternalResource(){const selectedId=$('channelExternalResource')?.value||'';if(selectedId&&state.externalResources?.external_resources?.[selectedId])return state.externalResources.external_resources[selectedId];const channelId=$('channelId')?.value?.trim?.()||'';const configured=channelId?state.channels?.channels?.[channelId]:null;return configured?.source_kind==='external'&&configured?.resource?state.externalResources?.external_resources?.[configured.resource]||null:null}
function updateChannelSourceVisibility(){const sourceMode=$('channelSourceMode')?.value||'local';const type=$('channelType')?.value||'di';const isExternal=sourceMode==='external';const ext=isExternal?getSelectedExternalResource():null;$('channelGpioWrap')?.classList.toggle('hidden',isExternal);$('channelExternalResourceWrap')?.classList.toggle('hidden',!isExternal);$('channelPullupWrap')?.classList.toggle('hidden',type!=='di'||isExternal);if(isExternal&&type==='di')$('channelPullup').checked=false;if($('channelSourceNote'))$('channelSourceNote').textContent=isExternal?(ext?'Внешний ресурс приходит от устройства '+(ext.device_id||'-')+' и использует общую модель bus -> device -> external resource -> channel -> signal. Сейчас quality: '+(ext.quality||'-')+', status: '+(ext.status||'-')+'.':'Внешний ресурс приходит от устройства на шине и использует общую модель bus -> device -> external resource -> channel -> signal.'): 'Локальный источник использует GPIO текущей платы и аппаратные возможности активной платы.'}
function channelProfileDescription(profile,type){if(type==='ao'){if(profile==='0_10v')return'Используй для внешнего DAC/выходного каскада, который интерпретирует сигнал как 0-10 В.';if(profile==='4_20ma')return'Подходит для токового выходного каскада 4-20 мА. Сейчас это metadata и инженерная шкала.';if(profile==='0_20ma')return'Подходит для токового выходного каскада 0-20 мА. Сейчас это metadata и инженерная шкала.';if(profile==='custom')return'Полностью ручной диапазон для нестандартного выходного устройства.';return'Сырой или пользовательский профиль. Для локального ESP32 AO v1 это DAC-пины 25/26, а для внешнего DAC удобно начинать с полного сырого диапазона устройства.'}if(profile==='0_10v')return'Профиль для измерения напряжения 0-10 В через подходящий внешний фронтенд или делитель.';if(profile==='4_20ma')return'Профиль для токовой петли 4-20 мА через шунт или специализированный входной фронтенд.';if(profile==='0_20ma')return'Профиль для токового входа 0-20 мА через подходящий фронтенд.';if(profile==='custom')return'Полностью ручная настройка диапазона и единиц. Подходит для нестандартных датчиков.';return'Сырой или пользовательский профиль без навязанной физической модели. Можно вручную задать диапазоны и единицы.'}
function updateChannelProfileNote(){if(!$('channelProfileNote'))return;const type=$('channelType').value;const profile=$('channelProfile').value;const ext=(($('channelSourceMode')?.value||'local')==='external')?getSelectedExternalResource():null;let note=channelProfileDescription(profile,type);if(ext&&ext.device_id){const device=state.devices?.devices?.[ext.device_id];const driver=(device?.driver||'').toLowerCase();if(type==='ai'&&driver==='ads1115')note+=' Для ADS1115 v1 сырой single-ended диапазон обычно удобно начинать с 0..32767.';if(type==='ao'&&driver==='mcp4728')note+=' Для MCP4728 v1 удобно начинать с raw 0..4095. Если физическая шкала ещё не определена, временно оставь engineering range таким же.';}$('channelProfileNote').textContent=note}
function applyExternalAnalogDefaults(){const type=$('channelType')?.value||'di';const isExternal=($('channelSourceMode')?.value||'local')==='external';const ext=isExternal?getSelectedExternalResource():null;if(!isExternal||!ext||!ext.device_id||!(type==='ai'||type==='ao'))return false;const device=state.devices?.devices?.[ext.device_id];const driver=(device?.driver||'').toLowerCase();const rawMinField=$('channelRawMin');const rawMaxField=$('channelRawMax');const engMinField=$('channelEngMin');const engMaxField=$('channelEngMax');const unitsField=$('channelUnits');if(!rawMinField||!rawMaxField||!engMinField||!engMaxField||!unitsField)return false;const currentMin=String(rawMinField.value||'');const currentMax=String(rawMaxField.value||'');const currentEngMin=String(engMinField.value||'');const currentEngMax=String(engMaxField.value||'');let applied=false;if(type==='ai'&&driver==='ads1115'){const shouldApply=currentMin==='0'&&(currentMax==='4095'||currentMax==='');if(shouldApply){rawMinField.value='0';rawMaxField.value='32767';applied=true}}if(type==='ao'&&driver==='mcp4728'){const shouldApplyRaw=currentMin==='0'&&(currentMax==='255'||currentMax==='4095'||currentMax==='');const shouldApplyEng=unitsField.value===''&&currentEngMin==='0'&&(currentEngMax==='100'||currentEngMax==='255'||currentEngMax==='4095'||currentEngMax==='');if(shouldApplyRaw){rawMinField.value='0';rawMaxField.value='4095';applied=true}if(shouldApplyEng){engMinField.value='0';engMaxField.value='4095';applied=true}}return applied}
function snapshotChannelCalibrationState(){return{profile:$('channelProfile').value,units:$('channelUnits').value,filter:$('channelFilter').value,filterAlpha:$('channelFilterAlpha').value,rawMin:$('channelRawMin').value,rawMax:$('channelRawMax').value,engMin:$('channelEngMin').value,engMax:$('channelEngMax').value,offset:$('channelOffset').value,scale:$('channelScale').value,clampEnabled:$('channelClampEnabled').checked,clampMin:$('channelClampMin').value,clampMax:$('channelClampMax').value}}
function beginChannelCalibrationSession(){state.ui.channelCalibration={snapshot:snapshotChannelCalibrationState(),lowRaw:null,highRaw:null,applied:false}}
function commitChannelCalibrationSession(){if(!$('channelCalibrationCard'))return;if($('channelType').value!=='ai'){state.ui.channelCalibration=null;return}beginChannelCalibrationSession();renderChannelCalibrationAssistant()}
function currentChannelRawValue(){const channelId=$('channelId').value.trim();if(!channelId)return null;const runtime=state.status?.channels?.[channelId];if(runtime?.value===undefined||runtime?.value===null)return null;const numeric=parseFloat(runtime.value);return Number.isFinite(numeric)?numeric:null}
function estimateChannelEngineeringFromForm(rawValue){const rawMin=parseFloat($('channelRawMin').value);const rawMax=parseFloat($('channelRawMax').value);const engMin=parseFloat($('channelEngMin').value);const engMax=parseFloat($('channelEngMax').value);const offset=parseFloat($('channelOffset').value)||0;const scale=parseFloat($('channelScale').value)||1;if(!Number.isFinite(rawValue)||!Number.isFinite(rawMin)||!Number.isFinite(rawMax)||!Number.isFinite(engMin)||!Number.isFinite(engMax)||!(rawMax>rawMin))return null;let normalized=(rawValue-rawMin)/(rawMax-rawMin);let engineering=engMin+normalized*(engMax-engMin);engineering=engineering*scale+offset;if($('channelClampEnabled').checked){const clampMin=parseFloat($('channelClampMin').value);const clampMax=parseFloat($('channelClampMax').value);if(Number.isFinite(clampMin)&&engineering<clampMin)engineering=clampMin;if(Number.isFinite(clampMax)&&engineering>clampMax)engineering=clampMax}return engineering}
function renderChannelCalibrationStatePills(rawPointsReady,engPointsReady,applied,hasChanges){if(!$('channelCalibrationStates'))return;const pills=[];pills.push('<span class="status-pill '+(state.ui.channelCalibration?.lowRaw!==null?'ok':'pending')+'">'+(state.ui.channelCalibration?.lowRaw!==null?'Низ захвачен':'Низ не захвачен')+'</span>');pills.push('<span class="status-pill '+(state.ui.channelCalibration?.highRaw!==null?'ok':'pending')+'">'+(state.ui.channelCalibration?.highRaw!==null?'Верх захвачен':'Верх не захвачен')+'</span>');pills.push('<span class="status-pill '+(engPointsReady?'ok':'warn')+'">'+(engPointsReady?'Границы корректны':'Проверь инженерные границы')+'</span>');pills.push('<span class="status-pill '+(applied?'ok':'pending')+'">'+(applied?'Шкала применена':'Шкала не применена')+'</span>');pills.push('<span class="status-pill '+(hasChanges?'warn':'ok')+'">'+(hasChanges?'Есть несохранённые изменения':'Форма совпадает с сохранённой базой')+'</span>');$('channelCalibrationStates').innerHTML=pills.join('')}
function renderChannelCalibrationAssistant(){if(!$('channelCalibrationCard'))return;const type=$('channelType').value;const isAi=type==='ai';$('channelCalibrationCard').classList.toggle('hidden',!isAi);if(!isAi)return;if(!state.ui.channelCalibration)beginChannelCalibrationSession();const rawNow=currentChannelRawValue();const lowRaw=state.ui.channelCalibration?.lowRaw;const highRaw=state.ui.channelCalibration?.highRaw;const applied=!!state.ui.channelCalibration?.applied;const lowEng=parseFloat($('channelCalLowEng').value);const highEng=parseFloat($('channelCalHighEng').value);const rawPointsReady=lowRaw!==null&&highRaw!==null;const engPointsReady=Number.isFinite(lowEng)&&Number.isFinite(highEng)&&highEng>lowEng;const rawOrderReady=rawPointsReady&&highRaw>lowRaw;const canApply=rawPointsReady&&engPointsReady&&rawOrderReady;const rows=[];rows.push('<div><span>Текущий raw</span><strong>'+(rawNow??'-')+'</strong></div>');rows.push('<div><span>Нижняя точка</span><strong>'+(lowRaw!==null?lowRaw:'не захвачена')+'</strong></div>');rows.push('<div><span>Верхняя точка</span><strong>'+(highRaw!==null?highRaw:'не захвачена')+'</strong></div>');$('channelCalibrationSummary').innerHTML=rows.join('');const steps=[];if(rawNow===null)steps.push('1. Открой существующий AI-канал и обнови Status, чтобы появился live raw.');else if(lowRaw===null)steps.push('1. Выставь нижнее инженерное значение и нажми «Захватить нижнюю точку».');else if(highRaw===null)steps.push('2. Выставь верхнее инженерное значение и нажми «Захватить верхнюю точку».');else if(!rawOrderReady)steps.push('3. Проверь raw-точки: верхняя должна быть больше нижней.');else if(!engPointsReady)steps.push('3. Проверь инженерные значения: верхнее должно быть больше нижнего.');else if(!applied)steps.push('3. Нажми «Применить к шкале», чтобы записать новую шкалу в форму.');else steps.push('4. Нажми «Проверить результат», сверяй Live Preview и потом сохрани канал.');if($('channelCalibrationStep'))$('channelCalibrationStep').textContent=steps.join(' ');const notes=[];if(rawNow===null)notes.push('Нет live raw значения. Открой существующий AI-канал и обнови Status.');if(rawPointsReady&&!rawOrderReady)notes.push('Верхняя raw-точка должна быть больше нижней.');if(Number.isFinite(lowEng)&&Number.isFinite(highEng)&&!(highEng>lowEng))notes.push('Верхнее инженерное значение должно быть больше нижнего.');if(canApply&&!applied)notes.push('Точки готовы. Нажми "Применить к шкале", чтобы обновить raw/engineering диапазоны.');if(applied)notes.push('Новая шкала уже применена в форму. Проверь результат и затем сохрани канал.');$('channelCalibrationNote').textContent=notes.join(' ')||'Захвати две точки и потом примени их к шкале канала.';const hasChanges=(lowRaw!==null||highRaw!==null)||snapshotChannelCalibrationState().rawMin!==state.ui.channelCalibration.snapshot.rawMin||snapshotChannelCalibrationState().rawMax!==state.ui.channelCalibration.snapshot.rawMax||snapshotChannelCalibrationState().engMin!==state.ui.channelCalibration.snapshot.engMin||snapshotChannelCalibrationState().engMax!==state.ui.channelCalibration.snapshot.engMax||snapshotChannelCalibrationState().offset!==state.ui.channelCalibration.snapshot.offset||snapshotChannelCalibrationState().scale!==state.ui.channelCalibration.snapshot.scale;renderChannelCalibrationStatePills(rawPointsReady&&rawOrderReady,engPointsReady,applied,hasChanges);if($('channelCaptureLow'))$('channelCaptureLow').disabled=(rawNow===null);if($('channelCaptureHigh'))$('channelCaptureHigh').disabled=(rawNow===null);if($('channelApplyCalibration'))$('channelApplyCalibration').disabled=!canApply; if($('channelRollbackCalibration'))$('channelRollbackCalibration').disabled=!hasChanges; if($('channelCheckCalibration'))$('channelCheckCalibration').disabled=!applied; if($('channelCalibrationCheckNote'))$('channelCalibrationCheckNote').textContent=applied?'Новая шкала уже в форме. Нажми «Проверить результат», затем сравни Live Preview и сохрани канал.':'После применения шкалы нажми «Проверить результат», затем проверь Live Preview и сохрани канал.'}
function captureChannelCalibrationPoint(which){if(!state.ui.channelCalibration)beginChannelCalibrationSession();const rawNow=currentChannelRawValue();if(rawNow===null){$('channelSaveStatus').textContent='Нет live raw значения для захвата точки';return}if(which==='low')state.ui.channelCalibration.lowRaw=rawNow;else state.ui.channelCalibration.highRaw=rawNow;state.ui.channelCalibration.applied=false;renderChannelCalibrationAssistant();$('channelSaveStatus').textContent=(which==='low'?'Нижняя':'Верхняя')+' точка захвачена'}
function applyChannelCalibrationPoints(){if(!state.ui.channelCalibration)beginChannelCalibrationSession();const lowRaw=state.ui.channelCalibration.lowRaw;const highRaw=state.ui.channelCalibration.highRaw;const lowEng=parseFloat($('channelCalLowEng').value);const highEng=parseFloat($('channelCalHighEng').value);if(lowRaw===null||highRaw===null){$('channelSaveStatus').textContent='Сначала захвати нижнюю и верхнюю raw-точки';return}if(!(highRaw>lowRaw)){ $('channelSaveStatus').textContent='Верхняя raw-точка должна быть больше нижней'; return }if(!Number.isFinite(lowEng)||!Number.isFinite(highEng)||!(highEng>lowEng)){ $('channelSaveStatus').textContent='Проверь нижнее и верхнее инженерные значения'; return }$('channelRawMin').value=String(lowRaw);$('channelRawMax').value=String(highRaw);$('channelEngMin').value=String(lowEng);$('channelEngMax').value=String(highEng);$('channelOffset').value='0';$('channelScale').value='1';state.ui.channelCalibration.applied=true;renderChannelConditioningSummary();renderChannelCalibrationAssistant();renderChannelPreview();$('channelSaveStatus').textContent='Новая шкала применена в форму. Следующий шаг: проверить результат и сохранить канал.'}
function checkChannelCalibrationResult(){const rawNow=currentChannelRawValue();const estimated=estimateChannelEngineeringFromForm(rawNow);const units=$('channelUnits').value?(' '+$('channelUnits').value):'';renderChannelPreview();renderChannelCalibrationAssistant();if(rawNow===null||estimated===null){$('channelSaveStatus').textContent='Не удалось оценить результат. Проверь live raw и диапазоны.';return}$('channelSaveStatus').textContent='При текущем raw '+rawNow+' шкала даст примерно '+estimated.toFixed(3)+units+'. Сверь это с Live Preview и сохрани канал.'}
function rollbackChannelCalibration(){const snapshot=state.ui.channelCalibration?.snapshot;if(!snapshot){$('channelSaveStatus').textContent='Нет исходных значений для отката';return}$('channelProfile').value=snapshot.profile;$('channelUnits').value=snapshot.units;$('channelFilter').value=snapshot.filter;$('channelFilterAlpha').value=snapshot.filterAlpha;$('channelRawMin').value=snapshot.rawMin;$('channelRawMax').value=snapshot.rawMax;$('channelEngMin').value=snapshot.engMin;$('channelEngMax').value=snapshot.engMax;$('channelOffset').value=snapshot.offset;$('channelScale').value=snapshot.scale;$('channelClampEnabled').checked=!!snapshot.clampEnabled;$('channelClampMin').value=snapshot.clampMin;$('channelClampMax').value=snapshot.clampMax;state.ui.channelCalibration.lowRaw=null;state.ui.channelCalibration.highRaw=null;state.ui.channelCalibration.applied=false;updateChannelProfileNote();renderChannelConditioningSummary();renderChannelCalibrationAssistant();renderChannelPreview();$('channelSaveStatus').textContent='Исходные значения восстановлены'}
function renderChannelConditioningSummary(){if(!$('channelConditioningCard'))return;const type=$('channelType').value;const isAnalog=type==='ai'||type==='ao';const sourceMode=$('channelSourceMode').value;const isExternal=sourceMode==='external';const ext=isExternal?getSelectedExternalResource():null;const device=ext?.device_id?state.devices?.devices?.[ext.device_id]:null;const driver=(device?.driver||'').toLowerCase();$('channelConditioningCard').classList.toggle('hidden',!isAnalog);if(!isAnalog)return;const rawMin=parseFloat($('channelRawMin').value);const rawMax=parseFloat($('channelRawMax').value);const engMin=parseFloat($('channelEngMin').value);const engMax=parseFloat($('channelEngMax').value);const offset=parseFloat($('channelOffset').value)||0;const scale=parseFloat($('channelScale').value)||1;const clampEnabled=$('channelClampEnabled').checked;const clampMin=parseFloat($('channelClampMin').value);const clampMax=parseFloat($('channelClampMax').value);const filter=$('channelFilter').value;const profile=$('channelProfile').value;const sourceLabel=isExternal?(ext?((ext.label||$('channelExternalResource').value)+' ('+($('channelExternalResource').value||'-')+')'):($('channelExternalResource').value||'-')):($('channelGpio').value?('GPIO'+$('channelGpio').value):'-');const rows=[];rows.push('<div><span>Профиль</span><strong>'+profile+'</strong></div>');rows.push('<div><span>Источник</span><strong>'+sourceLabel+'</strong></div>');if(ext){rows.push('<div><span>Устройство</span><strong>'+(ext.device_id||'-')+'</strong></div>');rows.push('<div><span>Driver</span><strong>'+(driver||'-')+'</strong></div>');rows.push('<div><span>Live raw</span><strong>'+(ext.raw_value??'-')+'</strong></div>')}rows.push('<div><span>Шкала</span><strong>'+rawMin+' .. '+rawMax+' -> '+engMin+' .. '+engMax+(($('channelUnits').value||'')?(' '+$('channelUnits').value):'')+'</strong></div>');rows.push('<div><span>Математика</span><strong>scale '+scale+', offset '+offset+'</strong></div>');rows.push('<div><span>Фильтр</span><strong>'+(filter==='ema'?'EMA':'нет')+(filter==='ema'?(', alpha '+($('channelFilterAlpha').value||'0')):'')+'</strong></div>');rows.push('<div><span>Clamp</span><strong>'+(clampEnabled?(clampMin+' .. '+clampMax):'выключен')+'</strong></div>');if(type==='ao')rows.push('<div><span>Startup</span><strong>'+(String($('channelStartupValue').value||'0'))+(($('channelUnits').value||'')?(' '+$('channelUnits').value):'')+'</strong></div>');$('channelConditioningSummary').innerHTML=rows.join('');const notes=[];if(!(rawMax>rawMin))notes.push('Проверь raw диапазон: максимум должен быть больше минимума.');if(!(engMax>engMin))notes.push('Проверь инженерный диапазон: максимум должен быть больше минимума.');if(clampEnabled&&!(clampMax>=clampMin))notes.push('Clamp настроен некорректно: максимум должен быть не меньше минимума.');if(!isExternal&&type==='ao'&&$('channelGpio').value&&$('channelGpio').value!=='25'&&$('channelGpio').value!=='26')notes.push('Локальный AO v1 реально рассчитан на DAC-пины GPIO25 и GPIO26.');if(isExternal&&ext){if(type==='ao'&&driver==='mcp4728')notes.push('MCP4728 v1 удобно настраивать от raw 0..4095. Если физическая шкала ещё не определена, оставь engineering range таким же и потом уточни под каскад/нагрузку.');notes.push('Внешний analog-ресурс уже реально связан с устройством '+(ext.device_id||'-')+'. Quality: '+(ext.quality||'-')+', status: '+(ext.status||'-')+'.');if(ext.timestamp_ms)notes.push('Последнее обновление runtime: '+ext.timestamp_ms+' мс.')}if(isExternal&&!ext)notes.push('Выбери внешний ресурс, чтобы увидеть live raw и статус устройства.');if(!isExternal&&type==='ai'&&state.diagnostics?.channels?.[$('channelId').value.trim()]?.min_raw!==undefined)notes.push('Можно взять live raw окно из диагностики как стартовую точку и потом подправить вручную.');$('channelConditioningNote').textContent=notes.join(' ')||'Шкала и обработка выглядят согласованно. Следующий шаг — сохранить канал и проверить live preview.'}
