function renderDiagnostics(){$('diagnosticNote').textContent=state.diagnostics?.note||'Diagnostics unavailable';const rows=Object.entries(state.diagnostics?.channels||{}).map(([id,c])=>{if(c.type==='ai')return '<tr><td>'+id+'</td><td>GPIO'+c.gpio+'</td><td colspan="2">AI live window</td><td>'+c.min_raw+'..'+c.max_raw+'</td><td>avg '+c.avg_raw+'</td><td>'+c.classification+'</td></tr>';return '<tr><td>'+id+'</td><td>GPIO'+c.gpio+'</td><td>'+boolBadge(c.expected_internal_pullup)+'</td><td>'+boolBadge(c.observed_pullup_effect)+'</td><td>'+c.without_pullup_high_count+'/16</td><td>'+c.with_pullup_high_count+'/16</td><td>'+c.classification+'</td></tr>'}).join('');$('diagnosticsTable').innerHTML=rows||'<tr><td colspan="7">No diagnostics available</td></tr>'}
