function updateNetworkVisibility(){const mode=$('wifiMode').value;const policy=$('wifiStartupPolicy').value;const showSta=mode==='sta'&&policy!=='ap_only';const showAp=mode==='ap'||policy!=='sta_only';const showOledCard=!!state.runtime?.modules?.oled;$('staSettingsCard').classList.toggle('hidden',!showSta);$('apSettingsCard').classList.toggle('hidden',!showAp);if($('oledNetworkCard'))$('oledNetworkCard').classList.toggle('hidden',!showOledCard)}
