function renderNetworkRuntime(){const runtime=state.runtime||{};const wifi=runtime.wifi||{};if($('networkRuntimeMode'))$('networkRuntimeMode').textContent=((wifi.mode||'-')+'').toUpperCase();if($('networkRuntimeIp'))$('networkRuntimeIp').textContent=runtime.ip||'-';if($('networkRuntimeSsid'))$('networkRuntimeSsid').textContent=wifi.ssid||wifi.ap_ssid||'-';if($('networkRuntimePolicy'))$('networkRuntimePolicy').textContent=wifi.startup_policy||'-';if($('networkRuntimeNote')){$('networkRuntimeNote').textContent=!state.runtime?'Runtime status ещё не загружен.':wifi.mode==='sta'?(runtime.ip?'Контроллер подключён к внешней сети и сейчас отвечает по указанному IP.':'STA режим активен, но IP ещё не выдан.'):'Контроллер работает в собственном AP режиме или ещё не завершил Wi-Fi переключение.'}}
function renderRequestTrace(){const entries=state.ui?.requestTrace||[];if($('requestTraceSummary'))$('requestTraceSummary').innerHTML='<div><span>Entries</span><strong>'+entries.length+'</strong></div><div><span>Latest</span><strong>'+(entries[0]?.url||'-')+'</strong></div><div><span>Status</span><strong>'+(entries[0]?.status||'-')+'</strong></div><div><span>Duration</span><strong>'+(entries[0]?.durationMs!==undefined?(entries[0].durationMs+' ms'):'-')+'</strong></div>';if($('requestTraceTable'))$('requestTraceTable').innerHTML=entries.map(entry=>'<tr><td>'+new Date(entry.startedAt).toLocaleTimeString()+'</td><td>'+entry.method+'</td><td class="mono">'+escapeHtml(entry.url)+'</td><td>'+(entry.ok?'<span class="badge safe">ok</span>':'<span class="badge warning">fail</span>')+'</td><td>'+(entry.status||'-')+'</td><td>'+(entry.durationMs||0)+' ms</td><td>'+(entry.size||0)+'</td><td>'+escapeHtml(entry.error||'-')+'</td></tr>').join('')||'<tr><td colspan="8">No request trace yet</td></tr>'}
function safeRender(label,fn){try{fn()}catch(error){const message='render '+label+': '+(error?.message||error);if($('runtimeOverview'))$('runtimeOverview').textContent=message+'\n\n'+($('runtimeOverview').textContent||'');window.recordRequestTrace?.({method:'UI',url:'render:'+label,ok:false,status:0,durationMs:0,size:0,startedAt:Date.now(),error:message})}}
function renderSettings(){renderNetworkRuntime();if(!state.runtime)return;const wifi=state.runtime.wifi||{};if($('wifiMode'))$('wifiMode').value=wifi.mode||'ap';if($('wifiStartupPolicy'))$('wifiStartupPolicy').value=wifi.startup_policy||'sta_fallback_ap';if($('wifiSsid'))$('wifiSsid').value=wifi.ssid||'';if($('wifiPassword'))$('wifiPassword').value=wifi.password||'';if($('wifiApSsid'))$('wifiApSsid').value=wifi.ap_ssid||'';if($('wifiApPassword'))$('wifiApPassword').value=wifi.ap_password||'';if($('wifiShowPasswords'))$('wifiShowPasswords').checked=false;if($('oledShowIpOnFallback'))$('oledShowIpOnFallback').checked=!!state.runtime.oled?.show_ip_on_fallback;const boardList=state.boards?.list||{};const names=Object.keys(boardList);if($('activeBoard')){$('activeBoard').innerHTML=names.map(n=>'<option value="'+n+'">'+n+'</option>').join('');$('activeBoard').value=state.runtime.active_board||names[0]||''}if($('toggleOled'))$('toggleOled').checked=!!state.runtime.modules?.oled;if($('toggleLora'))$('toggleLora').checked=!!state.runtime.modules?.lora;if($('toggleSd'))$('toggleSd').checked=!!state.runtime.modules?.sd;if($('toggleLed'))$('toggleLed').checked=!!state.runtime.modules?.led;if($('toggleBattery'))$('toggleBattery').checked=!!state.runtime.modules?.battery;if($('hardwareSaveStatus'))$('hardwareSaveStatus').textContent='Reservations follow saved config';updatePasswordVisibility();updateNetworkVisibility()}
async function refreshInspector(){state.inspector=await getJson(FEATURE_API.inspector||'/inspector');renderInspector();$('inspectorStatus').textContent='Updated '+new Date().toLocaleTimeString()}
function updateInspectorTimer(){if(state.ui.inspectorTimer){clearInterval(state.ui.inspectorTimer);state.ui.inspectorTimer=null}if($('inspectorAuto').checked){const interval=parseInt($('inspectorInterval').value,10)||500;state.ui.inspectorTimer=setInterval(()=>{refreshInspector().catch(e=>{$('inspectorStatus').textContent='Inspector error: '+e.message})},interval);$('inspectorStatus').textContent='Auto refresh enabled'}else{$('inspectorStatus').textContent='Inspector idle'}}
function applyLoadedState(partialState){if(!partialState)return;Object.entries(partialState).forEach(([key,value])=>{state[key]=value})}
function renderLoadedState(){safeRender('summary',()=>renderSummary());safeRender('hardware',()=>renderHardware());safeRender('channels',()=>renderChannels());safeRender('signals',()=>renderSignals());safeRender('signalOptions',()=>renderSignalOptions());if(typeof renderAlarmSignalOptions==='function')safeRender('alarmSignalOptions',()=>renderAlarmSignalOptions());if(typeof renderSequenceSignalOptions==='function')safeRender('sequenceSignalOptions',()=>renderSequenceSignalOptions());if(typeof renderDisplaySignalOptions==='function')safeRender('displaySignalOptions',()=>renderDisplaySignalOptions());safeRender('blocks',()=>renderBlocks());safeRender('blockOptions',()=>renderBlockOptions());safeRender('autoGpioOptions',()=>renderAutoGpioOptions());safeRender('blockOutputOptions',()=>renderBlockOutputOptions());safeRender('display',()=>renderDisplay());if(typeof renderAlarms==='function')safeRender('alarms',()=>renderAlarms());if(typeof renderSequences==='function')safeRender('sequences',()=>renderSequences());if(typeof renderComms==='function')safeRender('comms',()=>renderComms());if(featureSurfaceEnabled('editor')&&typeof renderEditor==='function')safeRender('editor',()=>renderEditor());if(featureSurfaceEnabled('modules')&&typeof renderModules==='function')safeRender('modules',()=>renderModules());safeRender('inspector',()=>renderInspector());safeRender('diagnostics',()=>renderDiagnostics());safeRender('settings',()=>renderSettings());safeRender('templates',()=>renderTemplates());safeRender('channelOptions',()=>renderChannelOptions());safeRender('channelConditioningSummary',()=>renderChannelConditioningSummary());safeRender('channelCalibrationAssistant',()=>renderChannelCalibrationAssistant());safeRender('channelPreview',()=>renderChannelPreview());safeRender('requestTrace',()=>renderRequestTrace())}
async function fetchFeatureBatch(entries,errors){const result={};for(const [key,url,fallback] of entries){result[key]=await safeGetJson(url,fallback,errors)}return result}
async function loadDeferredState(loadId){const errors=[];applyLoadedState(await fetchFeatureBatch([['signals',FEATURE_API.signals||'/signals',{signals:{}}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['display',FEATURE_API.display||'/display',{enabled:false,screens:{}}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['blocks',FEATURE_API.blocks||'/blocks',{blocks:{}}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['alarms',FEATURE_API.alarms||'/alarms',{alarms:{},recent_events:[],alarm_count:0,active_count:0}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['sequences',FEATURE_API.sequences||'/sequences',{sequences:{},recent_events:[],sequence_count:0,running_count:0,fault_count:0,done_count:0}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['buses',FEATURE_API.buses||'/buses',{buses:{}}],['devices',FEATURE_API.devices||'/devices',{devices:{}}],['externalResources',FEATURE_API.externalResources||'/external-resources',{external_resources:{}}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['inspector',FEATURE_API.inspector||'/inspector',{channels:{}}],['diagnostics',FEATURE_API.diagnostics||'/diagnostics',{channels:{}}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['templates',FEATURE_API.templateLibrary||'/template-library',{chip_templates:{},board_templates:{}}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();if(errors.length){$('runtimeOverview').textContent='Deferred load warnings:\n'+errors.join('\n')+'\n\n'+JSON.stringify(state.runtime,null,2);setSaveStatus('Loaded with warnings')}}
async function loadAll(){const errors=[];state.ui.loadGeneration=(state.ui.loadGeneration||0)+1;const loadId=state.ui.loadGeneration;applyLoadedState(await fetchFeatureBatch([['runtime',FEATURE_API.runtime||'/runtime',{wifi:{mode:'-'},detected_chip:{model:'-'},modules:{},active_board:'-'}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['boards',FEATURE_API.boards||'/boards',{active:'',list:{}}],['chip',FEATURE_API.chip||'/chip',{model:'-',revision:'-'}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();applyLoadedState(await fetchFeatureBatch([['hardware',FEATURE_API.hardware||'/hardware',{pins:[]}],['channels',FEATURE_API.channels||'/channels',{channels:{}}],['status',FEATURE_API.status||'/status',{channels:{}}]],errors));if(loadId!==state.ui.loadGeneration)return;renderLoadedState();if(errors.length){$('runtimeOverview').textContent='Partial bootstrap warnings:\n'+errors.join('\n')+'\n\n'+JSON.stringify(state.runtime,null,2);setSaveStatus('Loaded with warnings')}setTimeout(()=>{loadDeferredState(loadId).catch(e=>{$('runtimeOverview').textContent='Deferred load failed: '+e.message+'\n\n'+JSON.stringify(state.runtime,null,2);setSaveStatus('Loaded with warnings')})},0)}
async function bootstrapUi(attempt=0){try{await loadAll();setSaveStatus(attempt===0?'Ready':'Ready after retry')}catch(e){$('runtimeOverview').textContent='UI failed to load: '+e.message;setSaveStatus('Initial load failed');if(attempt<3){setTimeout(()=>bootstrapUi(attempt+1),250*(attempt+1))}}}
