async function saveSettings(){setSaveStatus('Saving settings...');$('hardwareSaveStatus').textContent='Saving reservations...';const payload={wifi:{mode:$('wifiMode').value,startup_policy:$('wifiStartupPolicy').value,ssid:$('wifiSsid').value,password:$('wifiPassword').value,ap_ssid:$('wifiApSsid').value,ap_password:$('wifiApPassword').value},system:{active_board:$('activeBoard').value},modules:{oled:$('toggleOled').checked,lora:$('toggleLora').checked,sd:$('toggleSd').checked,led:$('toggleLed').checked,battery:$('toggleBattery').checked},oled:{show_ip_on_fallback:$('oledShowIpOnFallback')?$('oledShowIpOnFallback').checked:true}};try{const r=await getJson(FEATURE_API.settings||'/settings',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const refreshOk=await refreshAfterSettingsSave();setSaveStatus(r.message||'Saved');$('hardwareSaveStatus').textContent=refreshOk?'Reservations saved':'Settings saved, some refresh calls failed';}catch(e){setSaveStatus('Save failed: '+e.message);$('hardwareSaveStatus').textContent='Save failed: '+e.message}}
async function saveChannel(){$('channelSaveStatus').textContent='Saving channel...';const type=$('channelType').value;const sourceMode=$('channelSourceMode').value;const payload={channel_id:$('channelId').value,type,source_mode:sourceMode,gpio:sourceMode==='local'?parseInt($('channelGpio').value,10):-1,external_resource_id:sourceMode==='external'?$('channelExternalResource').value:'',inverted:$('channelInverted').checked,pullup:$('channelPullup').checked,initial:$('channelInitial').checked,profile:$('channelProfile').value,units:$('channelUnits').value,filter:$('channelFilter').value,filter_alpha:parseFloat($('channelFilterAlpha').value)||0,raw_min:parseFloat($('channelRawMin').value)||0,raw_max:parseFloat($('channelRawMax').value)||0,eng_min:parseFloat($('channelEngMin').value)||0,eng_max:parseFloat($('channelEngMax').value)||0,offset:parseFloat($('channelOffset').value)||0,scale:parseFloat($('channelScale').value)||0,clamp_enabled:$('channelClampEnabled').checked,clamp_min:parseFloat($('channelClampMin').value)||0,clamp_max:parseFloat($('channelClampMax').value)||0,startup_value:parseFloat($('channelStartupValue').value)||0};if(type!=='ai'&&type!=='ao'){delete payload.profile;delete payload.units;delete payload.filter;delete payload.filter_alpha;delete payload.raw_min;delete payload.raw_max;delete payload.eng_min;delete payload.eng_max;delete payload.offset;delete payload.scale;delete payload.clamp_enabled;delete payload.clamp_min;delete payload.clamp_max;delete payload.startup_value}if(type!=='ao')delete payload.startup_value;try{const r=await getJson(FEATURE_API.channelBinding||'/channel-binding',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});await refreshBlockSurface();commitChannelCalibrationSession();renderChannelPreview();$('channelSaveStatus').textContent=r.message||'Channel saved'}catch(e){$('channelSaveStatus').textContent='Save failed: '+e.message}}
function resetChannelForm(){$('channelId').value='';$('channelType').value='di';$('channelSourceMode').value='local';$('channelInverted').checked=false;$('channelPullup').checked=false;$('channelInitial').checked=false;$('channelProfile').value='raw';$('channelUnits').value='';$('channelFilter').value='none';$('channelFilterAlpha').value='0.20';$('channelRawMin').value='0';$('channelRawMax').value='4095';$('channelEngMin').value='0';$('channelEngMax').value='100';$('channelOffset').value='0';$('channelScale').value='1';$('channelClampEnabled').checked=false;$('channelClampMin').value='0';$('channelClampMax').value='100';$('channelStartupValue').value='0';$('channelCalLowEng').value='0';$('channelCalHighEng').value='100';renderChannelOptions();updateChannelTypeVisibility();$('channelSaveStatus').textContent='Waiting for changes'}
function editChannel(id){const channel=state.channels?.channels?.[id];if(!channel)return;const binding=state.status?.channels?.[id];$('channelId').value=id;$('channelType').value=channel.type;$('channelSourceMode').value=channel.source_kind==='external'?'external':'local';$('channelInverted').checked=!!channel.inverted;$('channelPullup').checked=!!channel.pullup;$('channelInitial').checked=!!channel.initial;$('channelProfile').value=channel.profile||'raw';$('channelUnits').value=channel.units||'';$('channelFilter').value=channel.filter||'none';$('channelFilterAlpha').value=String(channel.filter_alpha??0.2);$('channelRawMin').value=String(channel.raw_min??0);$('channelRawMax').value=String(channel.raw_max??4095);$('channelEngMin').value=String(channel.eng_min??0);$('channelEngMax').value=String(channel.eng_max??100);$('channelOffset').value=String(channel.offset??0);$('channelScale').value=String(channel.scale??1);$('channelClampEnabled').checked=!!channel.clamp_enabled;$('channelClampMin').value=String(channel.clamp_min??0);$('channelClampMax').value=String(channel.clamp_max??100);$('channelStartupValue').value=String(channel.startup_value??0);$('channelCalLowEng').value=String(channel.eng_min??0);$('channelCalHighEng').value=String(channel.eng_max??100);renderChannelOptions();updateChannelTypeVisibility();if(channel.source_kind==='external'){$('channelExternalResource').value=channel.resource||''}else if(binding&&binding.gpio!==undefined&&binding.gpio>=0){$('channelGpio').value=String(binding.gpio)}beginChannelCalibrationSession();renderChannelConditioningSummary();renderChannelCalibrationAssistant();renderChannelPreview();$('channelSaveStatus').textContent='Editing '+id}
function prefillChannelFromExternalResource(resourceId){const resource=state.externalResources?.external_resources?.[resourceId];if(!resource)return;const capability=(resource.capability||'ai').toLowerCase();const suggestedId=String(resourceId).replace(/[^a-zA-Z0-9]+/g,'_').replace(/^_+|_+$/g,'');const tabBtn=document.querySelector('.tabs button[data-tab="channels"]');if(tabBtn)tabBtn.click();resetChannelForm();$('channelSourceMode').value='external';$('channelType').value=capability;$('channelId').value=suggestedId;$('channelUnits').value=resource.units||'';renderChannelOptions();$('channelExternalResource').value=resourceId;updateChannelTypeVisibility();renderChannelConditioningSummary();renderChannelCalibrationAssistant();renderChannelPreview();$('channelSaveStatus').textContent='Источник подготовлен из внешнего ресурса '+resourceId+'. Проверь ID и сохрани канал.'}
